const checkpoints = [];

const recipes = JSON.parse(localStorage.getItem('recipes') || '[]');
const collections = JSON.parse(localStorage.getItem('recipe_collections') || '[]');
const items = JSON.parse(localStorage.getItem('recipe_collection_items') || '[]');

const collection = collections.find(c => (c.name || '').toLowerCase().trim() === 'weeknight dinners');
let qualifyingCount = 0;

if (collection) {
  const collItems = items.filter(i => i.collectionId === collection.id);
  qualifyingCount = collItems.filter(ci => {
    const r = recipes.find(rcp => rcp.id === ci.recipeId);
    if (!r) return false;
    if (r.mealType !== 'dinner') return false;
    if (typeof r.servings !== 'number' || r.servings !== 4) return false;
    const total = typeof r.totalTimeMinutes === 'number'
      ? r.totalTimeMinutes
      : (typeof r.cookTimeMinutes === 'number' && typeof r.prepTimeMinutes === 'number'
        ? r.cookTimeMinutes + r.prepTimeMinutes
        : null);
    if (total === null || total > 45) return false;
    if (typeof r.caloriesPerServing !== 'number' || r.caloriesPerServing > 600) return false;
    if (typeof r.rating !== 'number' || r.rating < 4.0) return false;
    return true;
  }).length;
}

[1, 2, 3].forEach((n, idx) => {
  const weight = idx === 0 ? 0.34 : 0.33;
  checkpoints.push({ passed: qualifyingCount >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const activities = JSON.parse(localStorage.getItem('activities') || '[]');
const lists = JSON.parse(localStorage.getItem('activity_lists') || '[]');
const items = JSON.parse(localStorage.getItem('activity_list_items') || '[]');

const list = lists.find(l => (l.name || '').toLowerCase().trim() === 'rainy day plan');
let qualifyingCount = 0;

if (list) {
  const listItems = items.filter(i => i.listId === list.id);
  qualifyingCount = listItems.filter(li => {
    const a = activities.find(act => act.id === li.activityId);
    if (!a) return false;
    if (a.ageGroup !== 'years_5_8') return false;
    if (!(a.location === 'indoors' || a.location === 'mixed')) return false;
    if (a.costType !== 'free') return false;
    if (typeof a.costAmount === 'number' && a.costAmount !== 0) return false;
    if (typeof a.durationMinutes !== 'number' || a.durationMinutes > 60) return false;
    return true;
  }).length;
}

[1, 2, 3, 4, 5].forEach(n => {
  checkpoints.push({ passed: qualifyingCount >= n, weight: 0.2 });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const listItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

const now = new Date();
const twoYearsMs = 2 * 365 * 24 * 60 * 60 * 1000;

const qualifyingBookmarks = listItems.filter(li => {
  const a = articles.find(ar => ar.id === li.articleId);
  if (!a) return false;
  if (a.category !== 'wellbeing') return false;
  if (a.level !== 'beginner') return false;
  if (typeof a.sessionLengthMinutes !== 'number' || a.sessionLengthMinutes < 10 || a.sessionLengthMinutes > 15) return false;
  if (!a.publishDate) return false;
  const pubTime = new Date(a.publishDate).getTime();
  if (isNaN(pubTime) || (now.getTime() - pubTime) > twoYearsMs) return false;
  const cc = typeof a.commentCount === 'number' ? a.commentCount : 0;
  if (cc < 10) return false;
  return true;
});

checkpoints.push({ passed: qualifyingBookmarks.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const params = JSON.parse(localStorage.getItem('task4_filterParams') || 'null');
let comparedIdsRaw = localStorage.getItem('task4_comparedProductIds');
let comparedIds;
try {
  comparedIds = comparedIdsRaw ? JSON.parse(comparedIdsRaw) : [];
} catch (e) {
  comparedIds = Array.isArray(comparedIdsRaw) ? comparedIdsRaw : [];
}
const selectedId = localStorage.getItem('task4_selectedProductId') || null;

const products = JSON.parse(localStorage.getItem('products') || '[]');
const productLists = JSON.parse(localStorage.getItem('product_lists') || '[]');
const productListItems = JSON.parse(localStorage.getItem('product_list_items') || '[]');

// Qualifying yoga mats universe
const qualifyingMats = products.filter(p =>
  p.category === 'fitness_and_yoga' &&
  p.subcategory === 'yoga_mats' &&
  typeof p.price === 'number' && p.price < 60 &&
  typeof p.rating === 'number' && p.rating >= 4.5
);

let cheapest = null;
if (qualifyingMats.length > 0) {
  cheapest = qualifyingMats.reduce((min, p) => (!min || p.price < min.price ? p : min), null);
}

// CP1 (0.30): Used appropriate filter settings for category, price, and rating
const cp1Passed = !!(params &&
  params.category === 'fitness_and_yoga' &&
  typeof params.maxPrice === 'number' && params.maxPrice <= 60 &&
  typeof params.minRating === 'number' && params.minRating >= 4.5
);
checkpoints.push({ passed: cp1Passed, weight: 0.3 });

// CP2 (0.30): Compared at least two qualifying yoga mats under $60 with rating >= 4.5
const comparedQualifying = (Array.isArray(comparedIds) ? comparedIds : [])
  .map(id => products.find(p => p.id === id))
  .filter(p => !!p && p.category === 'fitness_and_yoga' && p.subcategory === 'yoga_mats' &&
    typeof p.price === 'number' && p.price < 60 &&
    typeof p.rating === 'number' && p.rating >= 4.5
  );

checkpoints.push({ passed: comparedQualifying.length >= 2, weight: 0.3 });

// CP3 (0.40): Added the cheapest qualifying mat to 'Home Gym' list and selected it
let homeGymList = productLists.find(l => (l.name || '').toLowerCase().trim() === 'home gym');
let hasCheapestInHomeGym = false;
if (homeGymList && cheapest) {
  hasCheapestInHomeGym = productListItems.some(i => i.listId === homeGymList.id && i.productId === cheapest.id);
}
const cp3Passed = !!(cheapest && hasCheapestInHomeGym && selectedId === cheapest.id);
checkpoints.push({ passed: cp3Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const prefsArr = JSON.parse(localStorage.getItem('newsletter_preferences') || '[]');
const pref = prefsArr[0] || null;

const requiredTopics = ['healthy_recipes', 'parenting_tips', 'mindfulness_and_self_care'];

let topicsOk = false;
let frequencyOk = false;
let scheduleOk = false;
let emailOk = false;

if (pref) {
  const topics = Array.isArray(pref.topics) ? pref.topics : [];
  const uniqueTopics = Array.from(new Set(topics));
  topicsOk = (uniqueTopics.length === requiredTopics.length) &&
    requiredTopics.every(t => uniqueTopics.includes(t));

  frequencyOk = pref.frequency === 'weekly';

  const day = (pref.dayOfWeek || '').toLowerCase();
  const time = pref.timeOfDay || '';
  scheduleOk = (day === 'monday' && time === '08:00');

  emailOk = pref.email === 'family_tester@example.com';
}

checkpoints.push({ passed: topicsOk, weight: 0.4 });
checkpoints.push({ passed: frequencyOk, weight: 0.2 });
checkpoints.push({ passed: scheduleOk, weight: 0.2 });
checkpoints.push({ passed: emailOk, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const comments = JSON.parse(localStorage.getItem('comments') || '[]');

const now = new Date();
const twelveMonthsMs = 365 * 24 * 60 * 60 * 1000;

const qualifyingComments = comments.filter(c => {
  if ((c.authorName || '').toLowerCase() !== 'jordan') return false;
  if (typeof c.text !== 'string') return false;
  const textLower = c.text.toLowerCase();
  if (!textLower.includes('family agreement')) return false;

  const article = articles.find(a => a.id === c.articleId);
  if (!article) return false;
  if (article.category !== 'parenting') return false;
  if (article.ageGroup !== 'years_9_12') return false;

  const topicNeedle = 'screen time rules';
  const hasTopic = [article.title, article.summary, article.content].some(field =>
    typeof field === 'string' && field.toLowerCase().includes(topicNeedle)
  ) || (Array.isArray(article.tags) && article.tags.some(t => (t || '').toLowerCase().includes('screen_time_rules')));
  if (!hasTopic) return false;

  if (!article.publishDate) return false;
  const pubTime = new Date(article.publishDate).getTime();
  if (isNaN(pubTime) || (now.getTime() - pubTime) > twelveMonthsMs) return false;

  const sentenceParts = c.text.split(/[.!?]+/).filter(s => s.trim().length > 0);
  if (sentenceParts.length !== 2) return false;

  return true;
});

checkpoints.push({ passed: qualifyingComments.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('planner_plans') || '[]');
const items = JSON.parse(localStorage.getItem('planner_plan_items') || '[]');
const activities = JSON.parse(localStorage.getItem('activities') || '[]');
const recipes = JSON.parse(localStorage.getItem('recipes') || '[]');

const weekendPlans = plans.filter(p => (p.name || '').toLowerCase().trim() === 'weekend fun');

let bestSat = 0;
let bestSun = 0;

weekendPlans.forEach(plan => {
  const planItems = items.filter(i => i.planId === plan.id);

  const satCount = planItems.filter(pi => {
    if (pi.itemType !== 'activity' || pi.dayOfWeek !== 'saturday') return false;
    const a = activities.find(act => act.id === pi.activityId);
    if (!a) return false;
    if (a.ageGroup !== 'years_3_6') return false;
    if (!(a.location === 'outdoors' || a.location === 'mixed')) return false;
    if (typeof a.durationMinutes !== 'number' || a.durationMinutes > 120) return false;
    return true;
  }).length;

  const sunCount = planItems.filter(pi => {
    if (pi.itemType !== 'recipe' || pi.dayOfWeek !== 'sunday') return false;
    const r = recipes.find(rec => rec.id === pi.recipeId);
    if (!r) return false;
    if (r.mealType !== 'snacks') return false;
    if (typeof r.prepTimeMinutes !== 'number' || r.prepTimeMinutes > 20) return false;
    const tags = Array.isArray(r.healthTags) ? r.healthTags : [];
    if (!tags.includes('healthy_snack')) return false;
    return true;
  }).length;

  if ((satCount + sunCount) > (bestSat + bestSun)) {
    bestSat = satCount;
    bestSun = sunCount;
  }
});

checkpoints.push({ passed: bestSat >= 1, weight: 0.25 });
checkpoints.push({ passed: bestSat >= 2, weight: 0.25 });
checkpoints.push({ passed: bestSun >= 1, weight: 0.25 });
checkpoints.push({ passed: bestSun >= 2, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const budgets = JSON.parse(localStorage.getItem('wellness_budgets') || '[]');
const categories = JSON.parse(localStorage.getItem('wellness_budget_categories') || '[]');

const now = new Date();
const upcoming = new Date(now.getFullYear(), now.getMonth() + 1, 1);
const monthNames = ['january', 'february', 'march', 'april', 'may', 'june', 'july', 'august', 'september', 'october', 'november', 'december'];
const targetMonth = monthNames[upcoming.getMonth()];
const targetYear = upcoming.getFullYear();

const budget = budgets.find(b => b.month === targetMonth && b.year === targetYear && b.totalAmount === 200);

let totalAndMonthOk = !!budget;
let categoriesIncludeRequired = false;
let categoriesExactMatch = false;

if (budget) {
  const catForBudget = categories.filter(c => c.budgetId === budget.id);
  const amountsByName = {};
  catForBudget.forEach(c => {
    if (typeof c.name === 'string') {
      amountsByName[c.name] = typeof c.amount === 'number' ? c.amount : amountsByName[c.name];
    }
  });

  const hasHealthyGroceries = amountsByName['Healthy Groceries'] === 80;
  const hasFamilyActivities = amountsByName['Family Activities'] === 70;
  const hasSubscriptions = amountsByName['Subscriptions'] === 50;

  categoriesIncludeRequired = hasHealthyGroceries && hasFamilyActivities && hasSubscriptions;

  categoriesExactMatch = categoriesIncludeRequired && catForBudget.length === 3;
}

checkpoints.push({ passed: totalAndMonthOk, weight: 0.3 });
checkpoints.push({ passed: categoriesIncludeRequired, weight: 0.3 });
checkpoints.push({ passed: categoriesExactMatch, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
